import { useState } from "react";

function Join({ setRoom, setPage }) {
  const [roomInput, setRoomInput] = useState("");

  return (
    <div>
      <h2>Войти в комнату</h2>

      <input
        placeholder="Код комнаты"
        onChange={(e) => setRoomInput(e.target.value)}
      />

      <button
        onClick={() => {
          setRoom(roomInput);
          setPage("room");
        }}
      >
        Войти
      </button>
    </div>
  );
}

export default Join;
